INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-26', E'하나님의 역사와 위로 (요한계시록 13장)', E'요한계시록 13장', E'요한계시록 13장은 용이 자신의 권세를 위임한 두 짐승의 등장을 통해 악의 세력이 어떻게 조직적으로 하나님의 백성을 공격하는지 보여줍니다. 바다에서 나온 첫째 짐승은 정치적 권세를 상징하며, 땅에서 나온 둘째 짐승은 종교적 미혹을 담당합니다. 이들은 서로 긴밀히 협력하며 온 세상을 기만하고 지배하려 합니다.\n\n첫째 짐승이 받은 권세는 실로 압도적입니다. "각 족속과 백성과 방언과 나라를 다스리는 권세"(계 13:7)를 받아 전 세계적 영향력을 행사합니다. 더욱 놀라운 것은 머리 하나가 죽었다가 다시 살아난 것처럼 보이는 이적을 통해 사람들의 경배를 받는다는 점입니다. 이는 그리스도의 부활을 모방한 거짓 기적으로, 많은 이들을 미혹하여 용과 짐승을 따르게 만듭니다. 둘째 짐승은 겉으로는 어린 양처럼 온순해 보이지만 실제로는 용처럼 말합니다. 종교적 권위를 가장하여 거짓 이적들을 행하고, 첫째 짐승의 우상을 만들어 경배를 강요합니다.\n\n가장 충격적인 것은 경제 체제를 통한 통제입니다. 짐승의 표를 받지 않으면 매매조차 할 수 없게 만들어, 일상생활 자체를 불가능하게 만듭니다. 이것은 단순한 핍박을 넘어 생존 자체를 위협하는 전면적인 압박입니다. 오늘날에도 우리는 신앙의 가치관과 세상의 체제가 충돌할 때 비슷한 압박을 경험합니다. 승진을 위해 양심을 버려야 하거나, 사업을 위해 신앙을 숨겨야 하는 상황들이 그것입니다.\n\n그러나 본문은 분명히 선언합니다. "성도들의 인내와 믿음이 여기 있느니라." 아무리 짐승의 권세가 강해 보여도, 그것은 한시적이며 제한적입니다. 창세 이후로 어린 양의 생명책에 기록된 이름은 결코 지워지지 않습니다. 하나님의 백성은 눈에 보이는 권세와 위협 앞에서도 믿음으로 인내하며, 끝까지 하나님께 속한 정체성을 지켜나갑니다. 이것이 바로 성도가 걸어가는 십자가의 길입니다.', E'오늘의 핵심\n악의 세력이 정치적 권세와 종교적 미혹, 경제적 통제로 총공세를 펼쳐도, 어린 양의 생명책에 기록된 성도들은 믿음과 인내로 승리합니다.\n\n묵상 질문\n1. 오늘날 나의 신앙을 위협하는 ''짐승의 표''는 어떤 모습으로 다가오고 있나요?\n2. 세상의 체제가 요구하는 타협 앞에서 어떻게 믿음의 정체성을 지킬 수 있을까요?\n3. "성도들의 인내와 믿음"을 위해 오늘 내가 붙잡아야 할 하나님의 약속은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-27', E'하나님의 역사와 위로 (요한계시록 14장)', E'요한계시록 14장', E'요한계시록 14장은 하나님의 백성과 세상의 극명한 대조를 통해 최종적인 운명의 갈림길을 보여줍니다. 시온 산에 선 어린 양과 십사만 사천 명의 모습은 13장에서 보았던 짐승의 표를 받은 무리와 완전히 대비됩니다. 이들의 이마에는 짐승의 표가 아닌 어린 양과 아버지의 이름이 새겨져 있습니다. 그들이 부르는 새 노래는 오직 구속받은 자들만이 배울 수 있는 특별한 찬양이었습니다.\n\n이들을 묘사하는 표현들은 우리에게 참된 제자도의 본질을 가르쳐줍니다. "어린 양이 어디로 인도하든지 따라가는 자"(계 14:4)라는 말씀은 단순히 종교적 의무를 수행하는 것이 아니라, 삶의 모든 영역에서 주님의 인도하심을 따르는 전인적인 헌신을 의미합니다. 그들의 입에 거짓말이 없다는 것은 진실함으로 세상과 구별된 삶을 살아가는 하나님 백성의 표지입니다.\n\n천사들이 전하는 세 가지 메시지는 인류에게 주어진 마지막 경고입니다. 첫째 천사는 창조주 하나님께 돌아오라고 외치고, 둘째 천사는 바벨론의 멸망을 선포하며, 셋째 천사는 짐승을 경배하는 자들의 운명을 경고합니다. 특히 짐승의 표를 받는 자들이 "밤낮 쉼을 얻지 못하리라"는 말씀과 "주 안에서 죽는 자들은 복이 있도다"라는 선언의 대조는 우리가 지금 이 순간 누구를 따르고 있는지 돌아보게 합니다.\n\n장의 마지막 부분에서는 곡식 추수와 포도 추수의 이중적 심판 장면이 펼쳐집니다. 익은 곡식을 거두는 것은 의인들의 구원을, 포도를 밟아 진노의 포도주를 만드는 것은 악인들의 심판을 상징합니다. 이 모든 장면은 우리에게 한 가지 분명한 메시지를 전달합니다. 지금이 바로 결단의 때라는 것입니다. 세상의 압력 속에서도 하나님의 계명과 예수님에 대한 믿음을 지키는 것, 그것이 성도들에게 요구되는 인내입니다.', E'오늘의 핵심\n시온 산에 선 어린 양을 따르는 자들과 짐승을 따르는 자들의 운명이 극명하게 대조되며, 하나님은 마지막 때에 자기 백성을 구별하여 영원한 안식으로 인도하십니다.\n\n묵상 질문\n1. 내 이마에는 누구의 이름이 새겨져 있나요? 일상에서 나는 누구를 따라가고 있나요?\n2. 세상의 성공과 안정을 좇는 삶과 어린 양을 따르는 삶 사이에서 나는 어떤 선택을 하고 있나요?\n3. "주 안에서 죽는 자들은 복이 있다"는 말씀이 오늘 나에게 주는 위로와 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-29', E'하나님의 역사와 위로 (요한계시록 15장)', E'요한계시록 15장', E'요한계시록 15장은 마지막 심판을 앞둔 장엄한 순간을 보여줍니다. 일곱 천사가 하나님의 진노를 완성할 마지막 재앙을 준비하는 가운데, 놀라운 장면이 펼쳐집니다. 불이 섞인 유리 바다 가에 선 이들은 짐승과 그 우상과 그 이름의 수를 이기고 벗어난 자들입니다. 그들이 손에 든 것은 무기가 아니라 하나님의 거문고였고, 그들이 부르는 것은 승리의 노래였습니다.\n\n이 노래는 단순한 찬양이 아닙니다. "하나님의 종 모세의 노래, 어린 양의 노래"(계 15:3)라는 표현은 출애굽의 구원과 십자가의 구원을 하나로 연결합니다. 홍해를 건넌 이스라엘 백성이 파라오의 군대로부터 구원받은 후 부른 노래처럼, 이들도 짐승의 권세로부터 구원받은 후 하나님께 영광을 돌립니다. 그들의 찬양은 하나님의 일이 "크고 놀라우시며" 그분의 길이 "의롭고 참되시다"는 고백으로 가득합니다. 박해와 시련 속에서도 끝까지 믿음을 지킨 이들에게 하나님의 의로우심은 더 이상 의문의 대상이 아니라 확실한 현실이 되었습니다.\n\n성전에서 나온 일곱 천사의 모습은 거룩함 그 자체입니다. 맑고 빛난 세마포 옷과 금띠는 순결과 영광을 상징하며, 그들이 받은 금 대접에는 영원히 살아계신 하나님의 진노가 가득 담겨 있습니다. 성전에 가득 찬 연기는 시내산에서 나타나신 하나님의 영광을 떠올리게 합니다. 아무도 성전에 들어갈 수 없다는 것은 이제 중보의 시간이 끝나고 최종 심판의 시간이 시작되었음을 의미합니다.\n\n그러나 이 엄중한 심판의 장면 속에서도 소망은 빛납니다. 유리 바다 가에 선 승리자들의 찬양은 고난을 통과한 모든 성도들에게 약속된 미래를 보여줍니다. 오늘 우리가 겪는 시련이 아무리 크더라도, 믿음으로 인내하는 자들에게는 하나님의 거문고를 들고 영원한 찬양을 부를 날이 기다리고 있습니다.', E'오늘의 핵심\n짐승의 권세를 이기고 승리한 성도들이 유리 바다 가에서 부르는 찬양은, 하나님의 의로우신 심판이 곧 성도들의 최종적 구원임을 선포합니다.\n\n묵상 질문\n1. 고난 속에서도 하나님의 의로우심을 신뢰하며 찬양할 수 있는 믿음이 내게 있나요?\n2. 짐승의 우상과 그 수를 이기려면 오늘 내가 거부해야 할 세상의 가치관은 무엇인가요?\n3. 모세의 노래와 어린 양의 노래를 부르는 승리자가 되기 위해 어떤 결단이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-30', E'공의로운 심판과 준비된 미래 (요한계시록 16장)', E'요한계시록 16장', E'하나님의 진노가 담긴 일곱 대접이 땅에 쏟아지기 시작합니다. 성전에서 울려 퍼진 큰 음성과 함께 일곱 천사가 각각의 대접을 쏟을 때마다 창조 질서가 무너지고 심판의 재앙이 확산되는 모습을 요한계시록 16장은 보여줍니다.\n\n첫째 대접이 쏟아지자 짐승의 표를 받고 우상에게 경배한 자들에게 악하고 독한 종기가 생깁니다. 둘째와 셋째 대접은 바다와 강물을 피로 변하게 하여 모든 수중 생물을 죽게 합니다. 이는 출애굽 당시 애굽에 내린 재앙을 연상시키면서도 그보다 훨씬 광범위하고 철저한 심판임을 보여줍니다. \n\n특별히 주목할 것은 물을 차지한 천사의 선언입니다. "전에도 계셨고 지금도 계신 거룩하신 이여 이렇게 심판하시니 의로우시도다"(계 16:5). 성도들과 선지자들의 피를 흘린 자들에게 피를 마시게 하시는 하나님의 심판이 합당하다는 천사의 고백은, 하나님의 공의로운 보응의 원칙을 분명히 드러냅니다.\n\n넷째 대접은 태양의 열기로 사람들을 태우고, 다섯째 대접은 짐승의 나라를 어둠으로 덮습니다. 그러나 놀랍게도 사람들은 이러한 재앙 속에서도 회개하지 않고 오히려 하나님을 비방합니다. 인간의 완고한 죄성이 얼마나 깊은지를 보여주는 장면입니다.\n\n여섯째 대접이 유브라데 강을 마르게 하여 동방 왕들의 길을 예비할 때, 용과 짐승과 거짓 선지자의 입에서 나온 더러운 영들이 온 천하 왕들을 아마겟돈으로 모읍니다. 이는 하나님을 대적하는 세력들의 최후 집결을 의미합니다.\n\n마침내 일곱째 대접이 공중에 쏟아지자 "되었다"는 음성과 함께 역사상 가장 큰 지진이 일어나고 큰 성 바벨론이 무너집니다. 바벨론의 붕괴는 하나님을 대적하는 모든 세상 권세의 종말을 상징합니다. 한 달란트나 되는 거대한 우박이 쏟아지는 가운데서도 사람들은 여전히 하나님을 비방합니다.\n\n이 모든 심판의 과정은 하나님께서 역사의 주권자이시며, 악에 대한 최종적인 심판자이심을 선포합니다. 동시에 끝까지 회개를 거부하는 인간의 완악함 앞에서 하나님의 인내와 공의가 어떻게 나타나는지를 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 일곱 대접 심판을 통해 악에 대한 철저한 보응과 함께 자신이 역사의 유일한 심판자이심을 나타내십니다.\n\n묵상 질문\n1. 재앙 속에서도 회개하지 않는 사람들의 모습이 오늘날 우리에게 주는 경고는 무엇일까요?\n2. "이렇게 심판하시니 의로우시도다"라는 천사의 고백이 내 삶에서는 어떤 의미로 다가오나요?\n3. 하나님의 최후 심판을 믿는 신앙이 오늘 나의 선택과 결정에 어떤 영향을 주고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-31', E'공의로운 심판과 준비된 미래 (요한계시록 17장)', E'요한계시록 17장', E'일곱째 천사가 대접을 쏟은 후 큰 성 바벨론의 멸망이 선포되었는데, 이제 천사가 요한에게 그 바벨론의 정체와 심판의 구체적인 모습을 보여줍니다. 요한이 본 환상 속에서 바벨론은 ''큰 음녀''의 모습으로 나타나며, 붉은 빛 짐승을 타고 있습니다. 이 여자는 자주 빛과 붉은 빛 옷을 입고 금과 보석으로 치장하여 겉으로는 화려하고 매혹적이지만, 그 손에 든 금잔에는 가증한 것과 음행의 더러운 것이 가득합니다.\n\n이 음녀의 정체는 하나님을 대적하고 성도들을 핍박하는 세상의 권력 체계를 상징합니다. 로마 제국은 일곱 언덕 위에 세워진 도시였고, 황제 숭배를 강요하며 기독교인들을 박해했습니다. 요한이 본 환상에서 이 여자가 "성도들의 피와 예수의 증인들의 피에 취한"(계 17:6) 모습은 바로 이러한 박해의 역사를 반영합니다. 그러나 이 바벨론은 단지 역사 속 로마만을 가리키는 것이 아니라, 모든 시대에 하나님을 대적하고 그의 백성을 핍박하는 세상 권력을 대표합니다.\n\n흥미로운 것은 이 음녀와 연합했던 열 뿔과 짐승이 결국 그녀를 배반하고 멸망시킨다는 점입니다. 악의 세력은 서로 연합하는 것처럼 보이지만 결국 스스로 분열하고 자멸하게 됩니다. 이것이 하나님의 섭리 가운데 이루어지는 심판의 방식입니다. 하나님께서는 악한 세력들이 서로를 파멸시키도록 허락하심으로써 그들의 심판을 이루십니다.\n\n그러나 이 모든 혼란과 심판 가운데서도 소망의 메시지가 선포됩니다. 어린 양이신 그리스도께서 "만주의 주시요 만왕의 왕"으로서 모든 대적을 이기실 것이며, 그와 함께 있는 "부르심을 받고 택하심을 받은 진실한 자들"도 함께 승리할 것입니다. 세상의 화려함과 권력이 아무리 강해 보여도 결국 하나님의 주권 앞에 무너질 것이며, 끝까지 신실하게 믿음을 지킨 성도들은 최후의 승리를 누리게 될 것입니다.', E'오늘의 핵심\n세상의 화려한 권력과 부는 일시적이며 스스로 멸망하지만, 어린 양이신 그리스도와 그를 따르는 신실한 성도들은 영원한 승리를 얻게 됩니다.\n\n묵상 질문\n1. 오늘날 나를 유혹하는 ''바벨론의 화려함''은 무엇이며, 그 이면의 공허함을 어떻게 분별하고 계신가요?\n2. 신앙 때문에 받는 고난 속에서도 ''만왕의 왕''이신 그리스도를 신뢰하며 살아가고 있나요?\n3. 세상의 가치관에 타협하지 않고 ''부르심을 받은 진실한 자''로 살기 위해 무엇을 결단해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-01', E'공의로운 심판과 준비된 미래 (요한계시록 18장)', E'요한계시록 18장', E'요한계시록 16장에서 일곱째 대접이 쏟아져 큰 성 바벨론이 무너진다는 선포가 있었다면, 18장은 그 바벨론의 멸망을 상세하게 보여주고 있습니다. 큰 권세를 가진 천사가 하늘에서 내려와 바벨론의 완전한 패망을 선언합니다. 한때 화려했던 그 도시는 이제 "귀신의 처소와 각종 더러운 영이 모이는 곳"이 되었다고 묘사됩니다.\n\n바벨론이 심판받는 이유가 무엇인지 본문은 분명히 밝히고 있습니다. 그것은 "음행의 진노의 포도주로 말미암아 만국이 무너졌으며"(계 18:3)라는 표현처럼, 하나님을 배반하고 우상을 섬기며 온 세상을 타락시킨 죄악 때문이었습니다. 특히 주목할 것은 바벨론의 죄가 단순히 종교적 배교에만 그치지 않았다는 점입니다. "땅의 상인들도 그 사치의 세력으로 치부하였도다"라는 구절이 보여주듯, 경제적 착취와 물질주의적 타락도 함께 얽혀 있었습니다.\n\n하늘로부터 또 다른 음성이 들려옵니다. "내 백성아, 거기서 나와 그의 죄에 참여하지 말고 그가 받을 재앙들을 받지 말라"는 이 부르심은 하나님의 백성들을 향한 긴급한 경고이자 사랑의 초청입니다. 세상의 화려함과 번영 속에 안주하며 살아가는 신앙인들에게, 하나님께서는 그 체제로부터 분리되어 나올 것을 명령하고 계십니다.\n\n바벨론의 멸망은 순식간에 일어납니다. "한 시간에" 모든 것이 무너진다는 표현이 반복되는 것은 하나님의 심판이 얼마나 신속하고 완전할 것인지를 보여줍니다. 왕들과 상인들, 선원들이 멀리 서서 바벨론의 불타는 연기를 보며 애통해하는 장면은 세상 권세의 허무함을 극적으로 드러냅니다. 그들이 슬퍼하는 이유는 바벨론의 죄악을 깨달아서가 아니라, 자신들의 부와 쾌락의 근원이 사라졌기 때문입니다.\n\n마지막 장면에서 힘센 천사가 큰 맷돌을 바다에 던지는 상징적 행동은 바벨론의 완전하고 영원한 멸망을 선언합니다. 음악 소리도, 일상의 소리도, 결혼의 기쁨도 다시는 그곳에서 들리지 않을 것입니다. 무엇보다 충격적인 것은 "선지자들과 성도들과 및 땅 위에서 죽임을 당한 모든 자의 피가 그 성 중에서 발견되었느니라"는 마지막 구절입니다. 화려한 문명의 이면에는 하나님의 백성을 핍박하고 죽인 피의 역사가 숨어 있었던 것입니다.', E'오늘의 핵심\n하나님께서는 그분을 대적하고 백성을 핍박한 바벨론의 죄악을 완전하고 신속하게 심판하시며, 동시에 자기 백성들에게는 그 멸망에서 나와 구별된 삶을 살라고 부르십니다.\n\n묵상 질문\n1. 오늘날 내가 살아가는 세상의 가치관과 하나님의 가치관 사이에서 어떤 갈등을 경험하고 있나요?\n2. "내 백성아, 거기서 나오라"는 하나님의 음성이 내게는 어떤 구체적인 결단을 요구하고 있을까요?\n3. 세상의 화려함과 번영이 한순간에 무너질 수 있다면, 나는 무엇을 붙잡고 살아가야 할까요?');
